 rows=''.join(f'<tr><th>{esc(s["title"].split(" — ")[0])}</th><td>●</td><td>●</td><td>●</td><td>○</td></tr>' for s in lane['sources'])
 trail=''.join(f'<li><a href="{esc(s["url"])}">{esc(s["title"])}</a></li>' for s in lane['sources'])
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Daily Ingest Dossier — {esc(lane['title'])} — {DATE}</title><meta name="lib:group" content="report"><meta name="lib:date" content="{DATE}"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Newsreader:opsz,wght@6..72,400;6..72,600&family=Plus+Jakarta+Sans:wght@400;500;600;700&display=swap" rel="stylesheet"><style>:root{{--brand:#01dc82;--deep:#033330;--lime:#cfe66a;--red:#b3261e;--amber:#9a6700;--ink:#0f172a;--muted:#475569;--line:#e2e8f0;--bg:#fafaf9;--card:#fff;--serif:"Newsreader",Georgia,serif;--sans:"Plus Jakarta Sans",system-ui,sans-serif}}*{{box-sizing:border-box}}body{{margin:0;background:var(--bg);color:var(--ink);font:15px/1.55 var(--sans)}}main{{max-width:64rem;margin:auto;padding:3rem 1.4rem 4rem}}h1,h2{{font-family:var(--serif);color:var(--deep);line-height:1.1}}h1{{font-size:2.3rem;margin:.7rem 0}}h2{{font-size:1.35rem;margin:.55rem 0}}a{{color:#087f51}}.wordmark{{display:flex;align-items:center;gap:.55rem;font-weight:700;color:var(--deep)}}.mark{{width:21px;height:21px;background:var(--brand);border-radius:5px;display:inline-block;transform:rotate(12deg)}}.date,.facts{{font:12px ui-monospace,monospace;color:var(--muted)}}.lead{{max-width:54rem;font-size:1.04rem}}.card,.item{{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:1.3rem;margin:1.2rem 0}}.diagram{{border:1px solid var(--line);border-radius:8px;padding:.75rem;background:#fff;margin:1rem 0}}svg{{display:block;width:100%;height:auto}}.label{{font:700 10px var(--sans);fill:#475569;letter-spacing:.08em}}.small{{font:12px var(--sans);fill:#475569}}.badges{{display:flex;gap:.45rem;flex-wrap:wrap}}.badge{{font-size:10px;letter-spacing:.06em;text-transform:uppercase;font-weight:700;background:#f1f5f9;color:var(--muted);padding:.18rem .45rem;border-radius:4px}}.good{{background:#dcfce7;color:#166534}}dl{{display:grid;grid-template-columns:9rem 1fr;gap:.35rem .8rem;margin:1rem 0}}dt{{font-weight:700;color:var(--deep)}}dd{{margin:0;color:#334155}}.action{{border-left:3px solid var(--brand);padding:.5rem .75rem;background:#effdf6;margin:1rem 0 0}}table{{width:100%;border-collapse:collapse;font-size:.85rem}}th,td{{border-bottom:1px solid var(--line);padding:.55rem;text-align:left}}td{{color:#087f51}}.callout{{border-left:3px solid var(--amber);padding:.65rem .85rem;background:#fffbeb;color:#713f12}}@media(max-width:560px){{dl{{grid-template-columns:1fr}}}}</style></head><body><main><header><div class="wordmark"><span class="mark" aria-hidden="true"></span>Buildn</div><p class="date">DAILY INGEST DOSSIER · {DATE}</p><h1>{esc(lane['title'])}</h1><p class="lead">{esc(lane['readout'])}</p></header><section class="card"><h2>Signal map</h2>{diagram(lane['slug'])}<p class="facts">selection rationale · {esc(lane['rationale'])}</p></section><section><h2>Dossier cards</h2>{cards}</section><section class="card"><h2>Use-case matrix</h2><table><thead><tr><th>Signal</th><th>Buildn OS</th><th>Client work</th><th>Agent workflows</th><th>Personal leverage</th></tr></thead><tbody>{rows}</tbody></table><p class="facts">● direct fit · ○ investigate only</p></section><section class="card"><h2>Top actions</h2><ol><li>Open the primary source and identify one bounded trial.</li><li>Define an owner, approval boundary, and success evidence.</li><li>Record result in the next operating review.</li></ol><p class="callout">Do not turn a fresh signal into a platform commitment before a reversible test.</p></section><section class="card"><h2>Source trail</h2><ul>{trail}</ul></section></main></body></html>'''
